// DepIDs returns a flat list of dependency IDs for this bead.
func (b *Bead) DepIDs() []string {
	var ids []string
	for _, d := range b.Dependencies {
		ids = append(ids, d.DependsOnID)
	}
	return ids
}

// HasDep returns true if the bead depends on the given ID.
func (b *Bead) HasDep(id string) bool {
	for _, d := range b.Dependencies {

	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		byID := make(map[string]*Bead, len(beads))
		// Reject duplicate IDs
		for i := range beads {
			e := &beads[i]
			byID[e.ID] = e
			if e.ID == b.ID {
				return fmt.Errorf("bead: duplicate id: %s", b.ID)
			}
		}
		// Validate deps reference existing beads
		depIDs := b.DepIDs()
		if len(depIDs) > 0 {
			existing := make(map[string]bool)
			for _, e := range beads {
				existing[e.ID] = true
			}
			for _, dep := range depIDs {
				if !existing[dep] {
					return fmt.Errorf("bead: dependency not found: %s", dep)
				}
			}
		}
		parentChain, err := beadParentChain(byID, b.Parent)
		if err != nil {
			return err
		}
		for _, depID := range depIDs {
			if err := rejectAncestorDependency(b.ID, depID, parentChain); err != nil {
				return err
			}
		}
		beads = append(beads, *b)
		return s.WriteAll(beads)
	})
}

// Get retrieves a bead by ID.
func (s *Store) Get(args ...any) (*Bead, error) {
	ctx := storeCallContext(args)
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	var id string
	for _, arg := range args {
		if s, ok := arg.(string); ok {
			id = s
			break
		}
	}
	if id == "" {
		return nil, fmt.Errorf("bead: get requires bead id")
	}
	beads, err := s.ReadAll(args...)
	if err != nil {
		return nil, err
	}
	for _, b := range beads {
		if b.ID == id {
			return &b, nil
		}
	}
	return nil, fmt.Errorf("bead: not found: %s", id)
}

