package bead

import (
	"encoding/json"
	"fmt"
	"time"
)

// Known field names that map to Bead struct fields (bd-compatible names).
var knownFields = map[string]bool{
	"id": true, "title": true, "issue_type": true, "status": true,
	"priority": true, "schema_version": true, "owner": true, "created_at": true, "created_by": true,
	"updated_at": true, "labels": true, "parent": true, "description": true,
	"acceptance": true, "dependencies": true, "notes": true,
	// Note: bd computed fields (dependency_count, dependent_count, comment_count)
	// are NOT in knownFields — they land in Extra and round-trip through it.
}

// unmarshalBead parses JSON into a Bead, preserving unknown fields in Extra.
func unmarshalBead(data []byte) (Bead, error) {
	var raw map[string]json.RawMessage
	if err := json.Unmarshal(data, &raw); err != nil {
		return Bead{}, fmt.Errorf("bead: unmarshal: %w", err)
	}

	var b Bead

	if v, ok := raw["id"]; ok {
		_ = json.Unmarshal(v, &b.ID)
	}
	if v, ok := raw["title"]; ok {
		_ = json.Unmarshal(v, &b.Title)
	}
	if v, ok := raw["issue_type"]; ok {
		_ = json.Unmarshal(v, &b.IssueType)
	}
	if v, ok := raw["schema_version"]; ok {
		_ = json.Unmarshal(v, &b.SchemaVersion)
	}
	if v, ok := raw["status"]; ok {
		_ = json.Unmarshal(v, &b.Status)
	}
	if v, ok := raw["priority"]; ok {
		_ = json.Unmarshal(v, &b.Priority)
	}
	if v, ok := raw["owner"]; ok {
		_ = json.Unmarshal(v, &b.Owner)
	}
	if v, ok := raw["created_at"]; ok {
		var t time.Time
		if err := json.Unmarshal(v, &t); err == nil {
			b.CreatedAt = t
		}
	}
	if v, ok := raw["created_by"]; ok {
		_ = json.Unmarshal(v, &b.CreatedBy)
	}
	if v, ok := raw["updated_at"]; ok {
		var t time.Time
		if err := json.Unmarshal(v, &t); err == nil {
			b.UpdatedAt = t
		}
	}
	if v, ok := raw["labels"]; ok {
		_ = json.Unmarshal(v, &b.Labels)
	}
	if v, ok := raw["parent"]; ok {
		_ = json.Unmarshal(v, &b.Parent)
	}
	if v, ok := raw["description"]; ok {
		_ = json.Unmarshal(v, &b.Description)
	}
	if v, ok := raw["acceptance"]; ok {
		_ = json.Unmarshal(v, &b.Acceptance)
	}
	if v, ok := raw["notes"]; ok {
		_ = json.Unmarshal(v, &b.Notes)
	}
	if v, ok := raw["dependencies"]; ok {
		_ = json.Unmarshal(v, &b.Dependencies)
	}

	// Defaults
	if b.IssueType == "" {
		b.IssueType = DefaultType
	}
	if b.SchemaVersion == 0 {
		b.SchemaVersion = CurrentSchemaVersion
	}
	if b.Status == "" {
		b.Status = DefaultStatus
	}

	// Collect unknown fields into Extra
	for k, v := range raw {
		if knownFields[k] {
			continue
		}
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		var val any
		_ = json.Unmarshal(v, &val)
		b.Extra[k] = val
	}

	return b, nil
}

// MarshalBead serializes a Bead to JSON, merging Extra fields back in.
// The output matches bd/br JSONL format.
func MarshalBead(b Bead) ([]byte, error) {
	return marshalBead(b)
}

func marshalBead(b Bead) ([]byte, error) {
	m := map[string]any{
		"id":             b.ID,
		"title":          b.Title,
		"status":         b.Status,
		"priority":       b.Priority,
		"issue_type":     b.IssueType,
		"schema_version": b.SchemaVersion,
		"created_at":     b.CreatedAt,
		"updated_at":     b.UpdatedAt,
	}

	// Optional fields — only include if non-empty
	if b.Owner != "" {
		m["owner"] = b.Owner
	}
	if b.CreatedBy != "" {
		m["created_by"] = b.CreatedBy
	}
	if len(b.Labels) > 0 {
		m["labels"] = b.Labels
	}
	if b.Parent != "" {
		m["parent"] = b.Parent
	}
	if b.Description != "" {
		m["description"] = b.Description
	}
	if b.Acceptance != "" {
		m["acceptance"] = b.Acceptance
	}
	if b.Notes != "" {
		m["notes"] = b.Notes
	}
	if len(b.Dependencies) > 0 {
		m["dependencies"] = b.Dependencies
	}

	// Merge extra fields (workflow-specific)
	for k, v := range b.Extra {
		if !knownFields[k] {
			m[k] = v
		}
	}

	return json.Marshal(m)
}

package bead

import (
	"encoding/json"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestBdSchemaCompatibility verifies that DDx bead JSONL output matches the
// bd (Dolt-backed bead tracker) schema exactly. This test locks in the field
// names so we never accidentally diverge from bd/br interchange format.
func TestBdSchemaCompatibility(t *testing.T) {
	// This is a real bd export line (from `bd export --format jsonl`)
	bdExport := `{"id":"bd-test-1x4","title":"test issue","status":"open","priority":2,"issue_type":"task","owner":"user@example.com","created_at":"2026-04-04T01:23:39Z","created_by":"Test User","updated_at":"2026-04-04T01:23:39Z","dependencies":[{"issue_id":"bd-test-1x4","depends_on_id":"bd-test-ioz","type":"blocks","created_at":"2026-04-03T21:23:54Z","created_by":"Test User","metadata":"{}"}],"dependency_count":1,"dependent_count":0,"comment_count":0}`

	// DDx must be able to unmarshal bd export without loss of known fields
	b, err := unmarshalBead([]byte(bdExport))
	require.NoError(t, err)

	assert.Equal(t, "bd-test-1x4", b.ID)
	assert.Equal(t, "test issue", b.Title)
	assert.Equal(t, "open", b.Status)
	assert.Equal(t, 2, b.Priority)
	assert.Equal(t, "task", b.IssueType)
	assert.Equal(t, "user@example.com", b.Owner)
	assert.Equal(t, "Test User", b.CreatedBy)
	assert.False(t, b.CreatedAt.IsZero())
	assert.False(t, b.UpdatedAt.IsZero())

	// Dependencies must be parsed
	require.Len(t, b.Dependencies, 1)
	assert.Equal(t, "bd-test-1x4", b.Dependencies[0].IssueID)
	assert.Equal(t, "bd-test-ioz", b.Dependencies[0].DependsOnID)
	assert.Equal(t, "blocks", b.Dependencies[0].Type)

	// bd-specific computed fields (dependency_count etc.) should be preserved in Extra
	assert.Equal(t, float64(1), b.Extra["dependency_count"])
	assert.Equal(t, float64(0), b.Extra["dependent_count"])
	assert.Equal(t, float64(0), b.Extra["comment_count"])
}

// TestBdRoundTrip verifies that a bd-exported bead survives DDx unmarshal→marshal
// without losing or renaming any fields.
func TestBdRoundTrip(t *testing.T) {
	bdExport := `{"id":"bd-test-abc","title":"Round trip","status":"open","priority":1,"issue_type":"epic","owner":"dev@co.com","created_at":"2026-01-01T00:00:00Z","created_by":"Dev","updated_at":"2026-02-01T00:00:00Z","custom_field":"preserved","dependency_count":0}`

	b, err := unmarshalBead([]byte(bdExport))
	require.NoError(t, err)

	// Marshal back
	out, err := marshalBead(b)
	require.NoError(t, err)

	// Parse the output and verify all original fields survive
	var result map[string]any
	require.NoError(t, json.Unmarshal(out, &result))

	// bd-compatible field names
	assert.Equal(t, "bd-test-abc", result["id"])
	assert.Equal(t, "Round trip", result["title"])
	assert.Equal(t, "open", result["status"])
	assert.Equal(t, float64(1), result["priority"])
	assert.Equal(t, "epic", result["issue_type"])
	assert.Equal(t, "dev@co.com", result["owner"])
	assert.Equal(t, "Dev", result["created_by"])

	// Custom fields preserved via Extra
	assert.Equal(t, "preserved", result["custom_field"])

	// Verify NO old DDx field names leak through
	assert.Nil(t, result["type"], "must use issue_type, not type")
	assert.Nil(t, result["assignee"], "must use owner, not assignee")
	assert.Nil(t, result["created"], "must use created_at, not created")
	assert.Nil(t, result["updated"], "must use updated_at, not updated")
	assert.Nil(t, result["deps"], "must use dependencies, not deps")
}

// TestDdxBeadFieldNames verifies that DDx-created beads use bd-compatible
// field names in their JSONL output.
func TestDdxBeadFieldNames(t *testing.T) {
	s := newTestStore(t)

	b := &Bead{Title: "New bead", IssueType: "task"}
	require.NoError(t, s.Create(testCtx(), b))

	// Marshal and check field names
	out, err := marshalBead(*b)
	require.NoError(t, err)

	var result map[string]any
	require.NoError(t, json.Unmarshal(out, &result))

	// Must use bd-compatible names
	assert.Contains(t, result, "issue_type", "must use issue_type")
	assert.Contains(t, result, "created_at", "must use created_at")
	assert.Contains(t, result, "updated_at", "must use updated_at")

	// Must NOT use old DDx names
	assert.NotContains(t, result, "type", "must not use 'type' (use issue_type)")
	assert.NotContains(t, result, "assignee", "must not use 'assignee' (use owner)")
	assert.NotContains(t, result, "created", "must not use 'created' (use created_at)")
	assert.NotContains(t, result, "updated", "must not use 'updated' (use updated_at)")
	assert.NotContains(t, result, "deps", "must not use 'deps' (use dependencies)")
}

package bead

import (
	"fmt"
	"sort"
	"strings"
)

// BlockReasonCode is the closed taxonomy of reasons an open bead is non-ready
// in the idle-path diagnosis pass. The full set is defined by FEAT-010
// §Idle-Path Diagnosis and Auto-Remediation; new codes require that spec to
// be updated.
type BlockReasonCode string

const (
	ReasonSupersededPendingClose              BlockReasonCode = "superseded_pending_close"
	ReasonClosureCandidateMisclassified       BlockReasonCode = "closure_candidate_misclassified"
	ReasonDeadIntermediateAllChildrenClosed   BlockReasonCode = "dead_intermediate_all_children_closed"
	ReasonDeadIntermediateOpenChildrenPending BlockReasonCode = "dead_intermediate_open_children_pending"
	ReasonEpicOfEpic                          BlockReasonCode = "epic_of_epic"
	ReasonDepBlockedBy                        BlockReasonCode = "dep_blocked_by"
	ReasonGenuinelyNeedsDecomposition         BlockReasonCode = "genuinely_needs_decomposition"
	ReasonParentChildStateConflict            BlockReasonCode = "parent_child_state_conflict"
	ReasonClaimedInProgress                   BlockReasonCode = "claimed_in_progress"
	ReasonProviderRouteUnavailable            BlockReasonCode = "provider_route_unavailable"
	ReasonGatedByBudgetOrCooldown             BlockReasonCode = "gated_by_budget_or_cooldown"
	ReasonMalformedParentOrDepRef             BlockReasonCode = "malformed_parent_or_dep_ref"
	ReasonDependencyCycle                     BlockReasonCode = "dependency_cycle"
	ReasonClosedOrMissingParent               BlockReasonCode = "closed_or_missing_parent"
	ReasonStaleGraphIndex                     BlockReasonCode = "stale_graph_index"
	ReasonAutoRemediationExhausted            BlockReasonCode = "auto_remediation_exhausted"
	ReasonNoDiagnosis                         BlockReasonCode = "no_diagnosis"
)

// BlockReason is a per-bead diagnosis of why a bead is non-ready. Detail is a
// human-readable string suitable for surfacing to operators; CitedIDs lists
// other bead IDs the reason references (deps, supersession targets, parents,
// cycle participants).
type BlockReason struct {
	Code     BlockReasonCode
	Detail   string
	CitedIDs []string
}

// Diagnose returns the first matching BlockReason for b according to the
// FEAT-010 §Idle-Path Diagnosis and Auto-Remediation taxonomy. The caller
// must pre-build the indexes:
//
//   - childIndex: parent_id -> every child bead (any status). Root beads are
//     keyed under the empty string. Diagnose also uses childIndex as the
//     global bead lookup; every referenced bead (supersession target, dep
//     target, parent) must appear in some entry for Diagnose to verify its
//     state.
//   - openChildIndex: parent_id -> open child beads only.
//   - depIndex: bead_id -> outgoing Dependency entries for that bead. Used
//     for global cycle detection across the dep DAG.
//
// Diagnose is pure: it performs no I/O, does not consult global state, and
// does not mutate its inputs.
func Diagnose(
	b Bead,
	childIndex map[string][]Bead,
	openChildIndex map[string][]Bead,
	depIndex map[string][]Dependency,
) BlockReason {
	// 1. superseded_pending_close
	if y := supersedingTargetID(b); y != "" {
		if target, ok := lookupBead(childIndex, y); ok && target.Status == StatusClosed {
			return BlockReason{
				Code:     ReasonSupersededPendingClose,
				Detail:   fmt.Sprintf("superseded by closed bead %s", y),
				CitedIDs: []string{y},
			}
		}
	}

	total := len(childIndex[b.ID])
	open := len(openChildIndex[b.ID])

	// 2. closure_candidate_misclassified — epic with closure-ready child set
	if isEpicBead(b) && total > 0 && open == 0 {
		return BlockReason{
			Code:   ReasonClosureCandidateMisclassified,
			Detail: fmt.Sprintf("epic %s has %d children, none open", b.ID, total),
		}
	}

	// 3 & 4. dead_intermediate_* — bead opted out of execution
	if eligible, set := lifecycleExecutionEligible(b); set && !eligible {
		if total > 0 && open == 0 {
			return BlockReason{
				Code:   ReasonDeadIntermediateAllChildrenClosed,
				Detail: "execution-eligible=false; all children closed",
			}
		}
		if open > 0 {
			ids := beadIDsFrom(openChildIndex[b.ID])
			return BlockReason{
				Code:     ReasonDeadIntermediateOpenChildrenPending,
				Detail:   fmt.Sprintf("execution-eligible=false; %d open child(ren) pending", open),
				CitedIDs: ids,
			}
		}
	}

	// 5. epic_of_epic — only open descendants are themselves epics
	if open > 0 {
		openChildren := openChildIndex[b.ID]
		if allEpicBeads(openChildren) {
			return BlockReason{
				Code:     ReasonEpicOfEpic,
				Detail:   "only open children are themselves epics",
				CitedIDs: beadIDsFrom(openChildren),
			}
		}
	}

	// 6. dep_blocked_by — unresolved outgoing deps
	if blockers := openDepBlockers(b, childIndex); len(blockers) > 0 {
		ids := make([]string, 0, len(blockers))
		details := make([]string, 0, len(blockers))
		for _, blk := range blockers {
			ids = append(ids, blk.ID)
			details = append(details, fmt.Sprintf("%s(status=%s)", blk.ID, blk.Status))
		}
		return BlockReason{
			Code:     ReasonDepBlockedBy,
			Detail:   "dep_blocked_by:" + strings.Join(details, ","),
			CitedIDs: ids,
		}
	}

	// 7. genuinely_needs_decomposition
	if isEpicBead(b) && total == 0 && !hasDecompositionOverrideLabel(b) {
		return BlockReason{
			Code:   ReasonGenuinelyNeedsDecomposition,
			Detail: "epic with no children and no manual-hold/no-auto-decompose/container override",
		}
	}

	// 8. parent_child_state_conflict
	if msg := parentChildConflict(b, childIndex); msg != "" {
		return BlockReason{
			Code:   ReasonParentChildStateConflict,
			Detail: msg,
		}
	}

	// 9. claimed_in_progress
	if b.Status == StatusInProgress {
		return BlockReason{
			Code:   ReasonClaimedInProgress,
			Detail: "bead currently claimed by an active worker",
		}
	}

	// 10. provider_route_unavailable
	if isProviderRouteUnavailable(b) {
		return BlockReason{
			Code:   ReasonProviderRouteUnavailable,
			Detail: "last dispatch: " + providerRouteHint(b),
		}
	}

	// 11. gated_by_budget_or_cooldown
	if gate := budgetOrCooldownGate(b); gate != "" {
		return BlockReason{
			Code:   ReasonGatedByBudgetOrCooldown,
			Detail: gate,
		}
	}

	// 12. malformed_parent_or_dep_ref
	if msg, cited := malformedRef(b, childIndex); msg != "" {
		return BlockReason{
			Code:     ReasonMalformedParentOrDepRef,
			Detail:   msg,
			CitedIDs: cited,
		}
	}

	// 13. dependency_cycle
	if cycle := detectDepCycle(b.ID, depIndex); len(cycle) > 0 {
		return BlockReason{
			Code:     ReasonDependencyCycle,
			Detail:   "cycle: " + strings.Join(cycle, "->"),
			CitedIDs: cycle,
		}
	}

	// 14. closed_or_missing_parent
	if b.Parent != "" {
		if parent, ok := lookupBead(childIndex, b.Parent); ok && parent.Status == StatusClosed {
			return BlockReason{
				Code:     ReasonClosedOrMissingParent,
				Detail:   fmt.Sprintf("parent %s is closed", b.Parent),
				CitedIDs: []string{b.Parent},
			}
		}
	}

	// 15. stale_graph_index
	if msg := staleIndexDisagreement(b, childIndex, openChildIndex); msg != "" {
		return BlockReason{
			Code:   ReasonStaleGraphIndex,
			Detail: msg,
		}
	}

	// 16. auto_remediation_exhausted
	if isAutoRemediationExhausted(b) {
		return BlockReason{
			Code:   ReasonAutoRemediationExhausted,
			Detail: "auto-remediation attempts cap hit or cooldown active",
		}
	}

	// 17. no_diagnosis (fallback)
	return BlockReason{
		Code:   ReasonNoDiagnosis,

